// Format leads into a morning briefing.
// Falls back to mock data if the leads API is unreachable.

const input = $input.first();
let leads;

if (input.json.statusCode && input.json.statusCode >= 400) {
  // API unreachable — use mock data for testing
  leads = [
    { name: 'John Smith', phone: '903-555-0100', status: 'New Lead', interest: '3BR Jessup single-section', source: 'Facebook Ad' },
    { name: 'Maria Garcia', phone: '903-555-0200', status: 'Follow-up', interest: 'Titanium 4BR multi-section', source: 'Walk-in' },
    { name: 'Robert Johnson', phone: '903-555-0300', status: 'Finance Review', interest: 'Jessup 2BR starter', source: 'Website' },
    { name: 'Ashley Williams', phone: '903-555-0400', status: 'Appointment Set', interest: 'Titanium energy-efficient 3BR', source: 'Referral' }
  ];
} else {
  leads = Array.isArray(input.json) ? input.json : [input.json];
}

const now = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/Chicago' });

let briefing = `MORNING BRIEFING — ${now}\n`;
briefing += `Longview Home Center\n`;
briefing += `${'='.repeat(40)}\n\n`;
briefing += `Total Active Leads: ${leads.length}\n\n`;

leads.forEach((lead, i) => {
  briefing += `${i + 1}. ${lead.name} (${lead.phone})\n`;
  briefing += `   Status: ${lead.status}\n`;
  briefing += `   Interest: ${lead.interest}\n`;
  briefing += `   Source: ${lead.source}\n\n`;
});

briefing += `---\nGenerated by AI MSP Testbed`;

return [{ json: { briefing, leadCount: leads.length, generatedAt: new Date().toISOString() } }];
